        const ny = h > 1 ? py / (h - 1) : 0;
        const sample = sampleField(field, nx, ny);
        const mag = sample.magnitude;
        const vMask = maskCenterY >= 0 ? Math.exp(-((ny - maskCenterY) ** 2) / (2 * maskSpread * maskSpread)) : 1;
