    const midHip = kp["midHip"];
    const rShoulder = kp["rShoulder"];
    const lShoulder = kp["lShoulder"];
    const rHip = kp["rHip"];
    const lHip = kp["lHip"];
    const ribcageCenter = kp["ribcageCenter"];
    const pelvisCenter = kp["pelvisCenter"];
