var MUSCLE_GROUPS = createMuscleGroups();
var anatomyRenderer = {
  method: "anatomy",
  render(keypoints, ctx, bounds, options) {
    blocksRenderer.render(keypoints, ctx, bounds, options);
    const extra = computeExtraKeypoints(keypoints);
    const allKp = { ...keypoints, ...extra };
    const kp = keypointsToPixels(allKp, bounds);
    ctx.lineWidth = options.lineWidth * 0.5;
    for (const muscle of MUSCLE_GROUPS) {
      const path = muscle.getPath(kp);
      if (path) {
        drawMuscle(ctx, path, muscle.color, options.transparency * 0.6);
      }
    }
    ctx.globalAlpha = 1;
  }
};

