function parsePoints(json) {
  try {
    const parsed = JSON.parse(json);
    if (!Array.isArray(parsed)) return [];
    return parsed;
  } catch {
    return [];
  }
}
function parseRhythmCurves(json) {
  try {
    const parsed = JSON.parse(json);
    if (!Array.isArray(parsed)) return [];
    return parsed;
  } catch {
    return [];
  }
}
function toPixelPoints(points, bounds) {
  return points.map((p) => ({
    x: bounds.x + p.x * bounds.width,
    y: bounds.y + p.y * bounds.height
  }));
}
var gestureLayerType = {
  typeId: "figure:gesture",
  displayName: "Gesture Line",
  icon: "gesture",
  category: "guide",
  properties: GESTURE_PROPERTIES,
  propertyEditorId: "figure:gesture-editor",
  createDefault() {
    const props = {};
    for (const schema of GESTURE_PROPERTIES) {
      props[schema.key] = schema.default;
    }
    return props;
  },
  render(properties, ctx, bounds, _resources) {
    const showLoA = properties.showLineOfAction ?? true;
    const showRhythm = properties.showRhythmCurves ?? true;
    const curveStyle = properties.curveStyle ?? "smooth";
    const taper = properties.taper ?? true;
    const taperAmount = properties.taperAmount ?? 0.7;
    const loaColor = properties.lineOfActionColor ?? "rgba(255,50,50,0.6)";
    const rhythmColor = properties.rhythmColor ?? "rgba(50,150,255,0.5)";
    const rhythmWidth = properties.rhythmWidth ?? 1.5;
    const lineWidth = properties.lineWidth ?? 1;
    ctx.save();
    if (showLoA) {
      const rawPoints = parsePoints(properties.lineOfAction ?? "[]");
      if (rawPoints.length >= 2) {
        const pixelPoints = toPixelPoints(rawPoints, bounds);
        const smoothed = curveStyle === "angular" ? pixelPoints : interpolatePath(pixelPoints, curveStyle === "organic" ? 12 : 8);
        ctx.strokeStyle = loaColor;
        ctx.setLineDash([]);
        if (taper) {
          drawTaperedCurve(ctx, smoothed, lineWidth * 3, taperAmount);
        } else {
          ctx.lineWidth = lineWidth * 2;
          drawBezierCurve(ctx, smoothed);
        }
      }
    }
    if (showRhythm) {
      const curves = parseRhythmCurves(properties.rhythmCurves ?? "[]");
      ctx.strokeStyle = rhythmColor;
      ctx.lineWidth = rhythmWidth;
      ctx.setLineDash([]);
      for (const curve of curves) {
        if (curve.points.length < 2) continue;
        const pixelPoints = toPixelPoints(curve.points, bounds);
        const smoothed = curveStyle === "angular" ? pixelPoints : interpolatePath(pixelPoints, curveStyle === "organic" ? 12 : 8);
        drawBezierCurve(ctx, smoothed);
        if (curve.label) {
          const mid = smoothed[Math.floor(smoothed.length / 2)];
          if (mid) {
            ctx.font = "11px sans-serif";
            ctx.fillStyle = rhythmColor;
            ctx.textAlign = "center";
            ctx.textBaseline = "bottom";
            ctx.fillText(curve.label, mid.x, mid.y - 5);
          }
        }
      }
    }
    ctx.restore();
  },
  validate(properties) {
    const errors = [];
    const ta = properties.taperAmount;
    if (typeof ta === "number" && (ta < 0 || ta > 1)) {
      errors.push({ property: "taperAmount", message: "Must be 0\\u20131" });
    }
    const rw = properties.rhythmWidth;
    if (typeof rw === "number" && (rw < 0.5 || rw > 5)) {
      errors.push({ property: "rhythmWidth", message: "Must be 0.5\\u20135" });
    }
    return errors.length > 0 ? errors : null;
  }
};

