function renderLoomisHead(ctx, cx, cy, radius, tiltX, tiltY, tiltZ, props) {
  const radX = tiltX * Math.PI / 180;
  const radY = tiltY * Math.PI / 180;
  const radZ = tiltZ * Math.PI / 180;
  const cosY = Math.cos(radY);
  const sinY = Math.sin(radY);
  const cosX = Math.cos(radX);
  ctx.setLineDash([]);
  drawEllipse(ctx, cx, cy, radius, radius);
  const sideOffset = radius * 0.85;
  const sideX = cx + sinY * sideOffset;
  const sideTop = cy - radius * 0.7;
  const sideBottom = cy + radius * 0.4;
  if (Math.abs(tiltY) > 5) {
    ctx.setLineDash([4, 3]);
    drawLine(ctx, sideX, sideTop, sideX, sideBottom);
  }
  if (props.showCrossLines) {
    ctx.setLineDash([4, 3]);
    const cvx = cx + sinY * radius * 0.1;
    const cvTop = cy - radius;
    const cvBottom = cy + radius;
    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate(radZ);
    ctx.translate(-cx, -cy);
    drawLine(ctx, cvx, cvTop, cvx, cvBottom + radius * props.jawLength);
    ctx.restore();
    const browY = cy + sinY * 0;
    const horizShift = radius * Math.sin(radX) * 0.3;
    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate(radZ);
    ctx.translate(-cx, -cy);
    drawEllipse(ctx, cx, cy + horizShift, radius * Math.abs(cosY), radius * 0.02 + Math.abs(Math.sin(radX)) * radius * 0.3);
    ctx.restore();
  }
  if (props.showJawPlane) {
    ctx.setLineDash([]);
    const jawW = radius * props.jawWidth;
    const jawH = radius * props.jawLength;
    const noseY = cy + radius * cosX * 0.95;
    const chinY = noseY + jawH * radius / radius;
    const jawLeftX = cx + sinY * radius * 0.1 - jawW * 0.5 * cosY;
    const jawRightX = cx + sinY * radius * 0.1 + jawW * 0.5 * cosY;
    const chinX = cx + sinY * radius * 0.15;
    ctx.beginPath();
    ctx.moveTo(jawLeftX, noseY);
    ctx.lineTo(chinX, chinY);
    ctx.lineTo(jawRightX, noseY);
    ctx.stroke();
    if (props.showChinLine) {
      ctx.setLineDash([2, 3]);
      drawLine(ctx, cx - radius, chinY, cx + radius, chinY);
    }
  }
  const guideLeft = cx - radius * 1.1;
  const guideRight = cx + radius * 1.1;
  if (props.showHairline) {
    ctx.setLineDash([2, 4]);
    ctx.globalAlpha = 0.4;
    const hairY = cy - radius * 0.67 + Math.sin(radX) * radius * 0.2;
    drawLine(ctx, guideLeft, hairY, guideRight, hairY);
    ctx.globalAlpha = 1;
  }
  if (props.showBrowLine) {
    ctx.setLineDash([3, 3]);
    ctx.globalAlpha = 0.6;
    const browY = cy + Math.sin(radX) * radius * 0.3;
    drawLine(ctx, guideLeft, browY, guideRight, browY);
    ctx.globalAlpha = 1;
  }
  if (props.showEyeLine) {
    ctx.setLineDash([2, 2]);
    ctx.globalAlpha = 0.5;
    const eyeY = cy + radius * 0.1 + Math.sin(radX) * radius * 0.3;
    drawLine(ctx, guideLeft, eyeY, guideRight, eyeY);
    ctx.globalAlpha = 1;
  }
  if (props.showNoseLine) {
    ctx.setLineDash([3, 3]);
    ctx.globalAlpha = 0.5;
    const noseY = cy + radius * cosX * 0.95;
    drawLine(ctx, guideLeft, noseY, guideRight, noseY);
    ctx.globalAlpha = 1;
  }
  if (props.showEarLine) {
    ctx.setLineDash([2, 4]);
    ctx.globalAlpha = 0.4;
    const earX = cx - sinY * radius * 0.6;
    const browY = cy + Math.sin(radX) * radius * 0.3;
    const noseY = cy + radius * cosX * 0.95;
    drawLine(ctx, earX, browY, earX, noseY);
    ctx.globalAlpha = 1;
  }
}
function renderSimpleHead(ctx, cx, cy, radius, tiltX, tiltY, tiltZ, props) {
  ctx.setLineDash([]);
  drawEllipse(ctx, cx, cy, radius * 0.8, radius);
  if (props.showCrossLines) {
    ctx.setLineDash([4, 3]);
    const radZ = tiltZ * Math.PI / 180;
    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate(radZ);
    drawLine(ctx, 0, -radius, 0, radius);
    const horizY = Math.sin(tiltX * Math.PI / 180) * radius * 0.3;
    drawLine(ctx, -radius * 0.8, horizY, radius * 0.8, horizY);
    ctx.restore();
  }
}
function renderAsaroHead(ctx, cx, cy, radius, tiltX, tiltY, tiltZ) {
  const sinY = Math.sin(tiltY * Math.PI / 180);
  const cosY = Math.cos(tiltY * Math.PI / 180);
  ctx.setLineDash([]);
  const r = radius;
  const frontW = r * 0.6 * cosY;
  const frontShift = sinY * r * 0.2;
  ctx.beginPath();
  ctx.moveTo(cx + frontShift - frontW, cy - r * 0.6);
  ctx.lineTo(cx + frontShift + frontW, cy - r * 0.6);
  ctx.lineTo(cx + frontShift + frontW * 0.9, cy + r * 0.3);
  ctx.lineTo(cx + frontShift, cy + r * 0.8);
  ctx.lineTo(cx + frontShift - frontW * 0.9, cy + r * 0.3);
  ctx.closePath();
  ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(cx + frontShift - frontW, cy - r * 0.6);
  ctx.lineTo(cx + frontShift, cy - r);
  ctx.lineTo(cx + frontShift + frontW, cy - r * 0.6);
  ctx.stroke();
  if (Math.abs(tiltY) > 10) {
    const sideSign = tiltY > 0 ? 1 : -1;
    const sideEdge = cx + frontShift + sideSign * frontW;
    const farEdge = sideEdge + sideSign * r * 0.3 * Math.abs(sinY);
    ctx.beginPath();
    ctx.moveTo(sideEdge, cy - r * 0.6);
    ctx.lineTo(farEdge, cy - r * 0.5);
    ctx.lineTo(farEdge, cy + r * 0.2);
    ctx.lineTo(sideEdge, cy + r * 0.3);
    ctx.stroke();
  }
  const cheekY = cy + r * 0.1;
  ctx.setLineDash([3, 3]);
  drawLine(ctx, cx + frontShift - frontW * 0.8, cheekY, cx + frontShift, cy + r * 0.8);
  drawLine(ctx, cx + frontShift + frontW * 0.8, cheekY, cx + frontShift, cy + r * 0.8);
}
