function applyDepthEasing(t, easing) {
  switch (easing) {
    case "linear":
      return t;
    case "quadratic":
      return t * t;
    case "cubic":
      return t * t * t;
    case "exponential": {
      const k = 3;
      return (Math.exp(k * t) - 1) / (Math.exp(k) - 1);
    }
  }
}
function computeDepth(normalizedY, config) {
  if (normalizedY <= config.horizonY) return 0;
  const t = (normalizedY - config.horizonY) / (1 - config.horizonY);
  return applyDepthEasing(Math.min(1, Math.max(0, t)), config.easing);
}
function applyDepthToParticle(depth, sizeMin, sizeMax, baseOpacity) {
  return {
    size: sizeMin + (sizeMax - sizeMin) * depth,
    opacity: baseOpacity * (0.3 + 0.7 * depth)
  };
}
function sampleDepthDistribution(rng, distribution) {
  const r = rng();
  switch (distribution) {
    case "uniform":
      return r;
    case "foreground-heavy":
      return Math.sqrt(r);
    // bias toward 1
    case "background-heavy":
      return 1 - Math.sqrt(1 - r);
    // bias toward 0
    case "midground":
      return (r + rng()) * 0.5;
  }
}

